Rule.Source:
  	import sailpoint.object.Custom;
  	
	String 	CUSTOM_OBJECT_NAME_MORRISEY		= "Ascension-Custom-Morrisey" ;
	
  	Custom custom=context.getObjectByName(Custom.class,CUSTOM_OBJECT_NAME_MORRISEY);
  	
  	List excludeIDNumbersList=custom.get("excludeIDNumbers");
  
	if (null == object.getAttribute("IDNumber") !=null && excludeIDNumbersList.contains(object.getAttribute("IDNumber"))) {  
		return null; 
	}   

    return object;
